using System.Reactive.Linq;
using MeshWeaver.Layout;
using MeshWeaver.Layout.Composition;

public record Story
{
    [Key]
    public string Id { get; init; } = string.Empty;

    [Required]
    public string Title { get; init; } = string.Empty;

    public string? Description { get; init; }

    /// <summary>
    /// The markdown content of the story.
    /// </summary>
    public string Markdown { get; init; } = string.Empty;

    public string IconName { get; init; } = "Document";

    public DateTimeOffset CreatedAt { get; init; } = DateTimeOffset.UtcNow;

    public DateTimeOffset? UpdatedAt { get; init; }
}

/// <summary>
/// Layout views for Story nodes.
/// </summary>
public static class StoryViews
{
    private const string StoryDataId = "story";
    private const string MarkdownDataId = "markdown";

    /// <summary>
    /// Details view - displays the markdown content as rendered markdown.
    /// </summary>
    public static UiControl Details(LayoutAreaHost host, RenderingContext ctx)
    {
        host.SubscribeToDataStream(StoryDataId, host.Workspace.GetNodeContent<Story>());

        return Controls.Stack
            .WithWidth("100%")
            .WithView(
                (h, c) => h.GetDataStream<Story>(StoryDataId)
                    .Select(story =>
                    {
                        if (story == null)
                            return Controls.Progress("Loading...", 0);

                        var stack = Controls.Stack
                            .WithWidth("100%")
                            .WithStyle("padding: 24px;");

                        // Header with edit button
                        var headerRow = Controls.Stack
                            .WithOrientation(Orientation.Horizontal)
                            .WithStyle("justify-content: space-between; align-items: center; margin-bottom: 16px;")
                            .WithView(Controls.Html($"<h1 style=\"margin: 0;\">{System.Web.HttpUtility.HtmlEncode(story.Title)}</h1>"))
                            .WithView(
                                Controls.Button("")
                                    .WithIconStart(FluentIcons.Edit())
                                    .WithClickAction(actx => actx.Host.UpdateArea(actx.Area, 
                                        new RedirectControl(new LayoutAreaReference("Editor").ToHref(host.Hub.Address)))));

                        stack = stack.WithView(headerRow);

                        if (!string.IsNullOrEmpty(story.Description))
                        {
                            stack = stack.WithView(Controls.Html($"<p style=\"color: #666; margin-bottom: 24px;\">{System.Web.HttpUtility.HtmlEncode(story.Description)}</p>"));
                        }

                        // Render markdown content
                        if (!string.IsNullOrEmpty(story.Markdown))
                        {
                            stack = stack.WithView(new MarkdownControl(story.Markdown).WithStyle("width: 100%;"));
                        }
                        else
                        {
                            stack = stack.WithView(Controls.Html("<p style=\"color: #888;\">No content yet. Click Edit to add content.</p>"));
                        }

                        return (UiControl)stack;
                    }),
                "Content"
            );
    }

    /// <summary>
    /// Editor view - displays a CodeEditor for editing the markdown content.
    /// </summary>
    public static UiControl Editor(LayoutAreaHost host, RenderingContext ctx)
    {
        host.SubscribeToDataStream(StoryDataId, host.Workspace.GetNodeContent<Story>());

        return Controls.Stack
            .WithWidth("100%")
            .WithView(
                (h, c) => h.GetDataStream<Story>(StoryDataId)
                    .Select(story => BuildEditorContent(host, story)),
                "Editor"
            );
    }

    private static UiControl BuildEditorContent(LayoutAreaHost host, Story? story)
    {
        var hubAddress = host.Hub.Address;
        var stack = Controls.Stack.WithWidth("100%").WithStyle("padding: 24px;");
        var markdownDataId = Guid.NewGuid().ToString("N").Substring(0, 8);
        var titleDataId = Guid.NewGuid().ToString("N").Substring(0, 8);
        var descriptionDataId = Guid.NewGuid().ToString("N").Substring(0, 8);

        var initialMarkdown = story?.Markdown ?? "";
        var initialTitle = story?.Title ?? "";
        var initialDescription = story?.Description ?? "";

        host.UpdateData(markdownDataId, initialMarkdown);
        host.UpdateData(titleDataId, initialTitle);
        host.UpdateData(descriptionDataId, initialDescription);

        // Title editor
        stack = stack.WithView(Controls.Stack
            .WithStyle("margin-bottom: 16px;")
            .WithView(Controls.Html("<label style=\"font-weight: 500; display: block; margin-bottom: 4px;\">Title:</label>"))
            .WithView(new TextFieldControl(new JsonPointerReference(""))
                .WithPlaceholder("Enter title...")
                .WithStyle("width: 100%;")
                .WithImmediate(true) with
            { DataContext = LayoutAreaReference.GetDataPointer(titleDataId) }));

        // Description editor
        stack = stack.WithView(Controls.Stack
            .WithStyle("margin-bottom: 16px;")
            .WithView(Controls.Html("<label style=\"font-weight: 500; display: block; margin-bottom: 4px;\">Description:</label>"))
            .WithView(new TextFieldControl(new JsonPointerReference(""))
                .WithPlaceholder("Enter description...")
                .WithStyle("width: 100%;")
                .WithImmediate(true) with
            { DataContext = LayoutAreaReference.GetDataPointer(descriptionDataId) }));

        // Markdown editor label
        stack = stack.WithView(Controls.Html("<label style=\"font-weight: 500; display: block; margin-bottom: 8px;\">Content (Markdown):</label>"));

        // Monaco editor for markdown
        var editor = new CodeEditorControl()
            .WithLanguage("markdown")
            .WithHeight("500px")
            .WithLineNumbers(true)
            .WithMinimap(false)
            .WithWordWrap(true)
            .WithPlaceholder("Enter markdown content...") with
        {
            DataContext = LayoutAreaReference.GetDataPointer(markdownDataId),
            Value = new JsonPointerReference("")
        };

        stack = stack.WithView(editor);

        // Button row
        var buttonRow = Controls.Stack
            .WithOrientation(Orientation.Horizontal)
            .WithStyle("gap: 8px; margin-top: 16px;");

        // Save button
        buttonRow = buttonRow.WithView(Controls.Button("Save")
            .WithAppearance(Appearance.Accent)
            .WithIconStart(FluentIcons.Save())
            .WithClickAction(async actx =>
            {
                var currentMarkdown = await host.Stream.GetDataStream<string>(markdownDataId).FirstAsync();
                var currentTitle = await host.Stream.GetDataStream<string>(titleDataId).FirstAsync();
                var currentDescription = await host.Stream.GetDataStream<string>(descriptionDataId).FirstAsync();

                var updatedStory = (story ?? new Story()) with
                {
                    Title = currentTitle,
                    Description = string.IsNullOrWhiteSpace(currentDescription) ? null : currentDescription,
                    Markdown = currentMarkdown,
                    UpdatedAt = DateTimeOffset.UtcNow
                };

                using var cts = new CancellationTokenSource(10.Seconds());
                var response = await actx.Host.Hub.AwaitResponse<DataChangeResponse>(
                    new DataChangeRequest().WithUpdates(updatedStory),
                    o => o.WithTarget(hubAddress),
                    cts.Token);

                if (response.Message.Log.Status != ActivityStatus.Succeeded)
                {
                    var errorDialog = Controls.Dialog(
                        Controls.Markdown($"**Error saving story:**\n\n{response.Message.Log}"),
                        "Save Failed"
                    ).WithSize("M");
                    actx.Host.UpdateArea(DialogControl.DialogArea, errorDialog);
                    return;
                }

                // Navigate back to details view
                var detailsHref = new LayoutAreaReference("Details").ToHref(hubAddress);
                actx.Host.UpdateArea(actx.Area, new RedirectControl(detailsHref));
            }));

        // Cancel button
        var detailsHref = new LayoutAreaReference("Details").ToHref(hubAddress);
        buttonRow = buttonRow.WithView(Controls.Button("Cancel")
            .WithAppearance(Appearance.Neutral)
            .WithClickAction(actx => actx.Host.UpdateArea(actx.Area, new RedirectControl(detailsHref))));

        stack = stack.WithView(buttonRow);

        return stack;
    }
}
